// Actualizar timestamps dinámicamente para que los partidos
// siempre estén en el futuro al momento de ejecutar la prueba
const now = Math.floor(Date.now() / 1000);
mockData.events = mockData.events.map(e => {
  if (e.timestamp !== null && e.id !== 1006) {
    // Recalcular timestamp según offset original
    const offsetsHoras = {
      1001: 6,  1002: 20, 1003: 20, 1004: 20,
      1005: 6,  1007: 47, 1008: 50, 1009: 6,
      1010: 20, 1011: 6,  1012: 20, 1013: null,
      1014: 6,  1015: 6,  1016: 6
    };
    const horas = offsetsHoras[e.id];
    if (horas !== null && horas !== undefined) {
      e.timestamp = now + (horas * 3600);
    }
  } else if (e.id === 1006) {
    // Partido ya iniciado: siempre en el pasado
    e.timestamp = now - (2 * 3600);
  }
  return e;
});

