return [{ json: mockData }];

const hoy = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Lima' });

const getFecha = (r) => {
  for (const k of ['LastUpdated','last_updated','Last Updated','updated_at','UpdatedAt','fecha']) {
    if (r[k]) { const d=new Date(r[k]); if(!isNaN(d)) return d.toLocaleDateString('en-CA',{timeZone:'America/Lima'}); }
  }
  for (const [k,v] of Object.entries(r)) {
    if (typeof v==='string' && /^\d{4}-\d{2}-\d{2}/.test(v)) {
      const d=new Date(v); if(!isNaN(d)) return d.toLocaleDateString('en-CA',{timeZone:'America/Lima'});
    }
  }
  return null;
};

const registros = items.map(i=>i.json).filter(r => getFecha(r)===hoy);

if (registros.length===0) {
  return [{ json: { rankingMsg:`🏆 Ranking — sin datos para hoy (${hoy})`, ranking:[], totalRegistros:0 }}];
}

// Ranking de casas
const conteo = {};
registros.forEach(r => {
  [r.BookmakerHome, r.BookmakerDraw, r.BookmakerAway].forEach(bk => {
    if (bk) conteo[bk] = (conteo[bk]||0)+1;
  });
});
const totalOps = registros.length * 3;
const sorted = Object.entries(conteo)
  .map(([bk,total]) => ({ bookmaker:bk, total, pct:((total/totalOps)*100).toFixed(1) }))
  .sort((a,b)=>b.total-a.total);
const top10 = sorted.slice(0,10);

// Resumen surebets del día
const surebets = registros.filter(r => (r.Tipo||'').toLowerCase()==='surebet');
const beneficios = surebets.map(r=>parseFloat(r.BeneficioPct||0)).filter(v=>!isNaN(v));
const beneficioPromedio = beneficios.length>0 ? (beneficios.reduce((a,b)=>a+b,0)/beneficios.length).toFixed(2) : '0.00';
const beneficioMax = beneficios.length>0 ? Math.max(...beneficios).toFixed(2) : '0.00';

const fecha = new Date().toLocaleDateString('es-PE',{timeZone:'America/Lima',day:'2-digit',month:'2-digit',year:'numeric'});

let msg = `🏆 Ranking de Casas — ${fecha}\n`;
msg += `📊 ${registros.length} partidos/mercados analizados hoy\n\n`;

top10.forEach((c,i) => {
  const medal = i===0?'🥇':i===1?'🥈':i===2?'🥉':`${i+1}.`;
  msg += `${medal} ${c.bookmaker} — mejor cuota ${c.pct}% de las veces\n`;
});

msg += `\n💡 Abre cuenta primero en:\n`;
msg += top10.slice(0,3).map((c,i)=>`  ${i+1}. ${c.bookmaker}`).join('\n');

msg += `\n\n━━━━━━ 📈 RESUMEN DEL DÍA ━━━━━━\n`;
if (surebets.length>0) {
  msg += `✅ Surebets detectadas: ${surebets.length}\n`;
  msg += `📊 Beneficio promedio: ${beneficioPromedio}%\n`;
  msg += `🏆 Mejor oportunidad: ${beneficioMax}%\n`;
  msg += `\n💰 Si hubieras ejecutado todas con S/500:\n`;
  const ganancia = beneficios.reduce((a,b)=>a+(500*(b/100)),0);
  msg += `   Ganancia acumulada estimada: S/${ganancia.toFixed(2)}`;
} else {
  msg += `ℹ️ Hoy no se detectaron surebets confirmadas\n`;
  msg += `   (normal — ocurren 0-3 veces por día en promedio)`;
}

return [{ json: { rankingMsg:msg, ranking:sorted, totalRegistros:registros.length, surebetsHoy:surebets.length }}];

// Filtrar partidos por ventana de tiempo
// timestamp en el scraper = Unix seconds (entero)
const cfg = $('CONFIG').first().json;
const maxHoras = cfg.CFG_MAX_HORAS_AL_PARTIDO ?? 48;

return items.filter(item => {
  const ts = item.json.timestamp;
  if (ts === null || ts === undefined) return true;

  // Unix timestamp en segundos → multiplicar por 1000 para ms
  const matchTime = Number(ts) * 1000;
  const now = Date.now();

  // Descartar partidos ya iniciados
  if (matchTime <= now) return false;

  const horasRestantes = (matchTime - now) / (1000 * 60 * 60);
  return horasRestantes <= maxHoras;
}).map(item => ({
  json: {
    ...item.json,
    horasRestantes: parseFloat(
      ((Number(item.json.timestamp) * 1000 - Date.now()) / (1000 * 60 * 60)).toFixed(1)
    )
  }
}));

const cfg = $('CONFIG').first().json;
const umbralMejora  = cfg.CFG_ALERTA_MEJORA_PCT ?? 1.0;
const umbralCierre  = cfg.CFG_MIN_BENEFICIO_PCT ?? 0.5;

return items.map(item => {
  const d = item.json;

  const beneficioActual = d.beneficioPct ?? 0;
  const tipo            = d.tipo   ?? 'ninguno';
  const riesgo          = d.riesgo ?? 'alto';
  const confianza       = d.confianza ?? 0;

  const alertSent       = $('Function - AttachLastHash').item.json.AlertSent ?? false;
  const beneficioPrevio = parseFloat($('Function - AttachLastHash').item.json.BeneficioPct ?? 0);

  // Condiciones base
  const condicionesBase = (
    beneficioActual > umbralCierre &&
    tipo      !== 'ninguno' &&
    riesgo    !== 'alto'    &&
    confianza >= (cfg.CFG_MIN_CONFIANZA ?? 50)
  );

  let debeAlertar    = false;
  let esSegundaAlerta = false;
  let oportunidadCerrada = false;
  let mejora = 0;

  if (!alertSent) {
    // Primera vez — alertar si cumple condiciones base
    debeAlertar = condicionesBase;
  } else {
    // Ya se alertó antes
    mejora = beneficioActual - beneficioPrevio;

    if (condicionesBase && mejora >= umbralMejora) {
      // Mejoró significativamente — segunda alerta
      debeAlertar     = true;
      esSegundaAlerta = true;
    } else if (beneficioPrevio >= umbralCierre && beneficioActual < umbralCierre) {
      // Oportunidad que antes era válida ahora cayó por debajo del umbral
      debeAlertar        = true;
      oportunidadCerrada = true;
    }
  }

  return {
    json: {
      ...d,
      debeAlertar,
      esSegundaAlerta,
      oportunidadCerrada,
      mejora: parseFloat(mejora.toFixed(3)),
      beneficioPrevio
    }
  };
});

return items.map(item => {
  const out   = { ...item.json };
  const market = out.market || '1X2';

  out.beneficioPctFmt = `${Number(out.beneficioPct??0).toFixed(2)}%`;
  const gan = out.gananciaEsperada ?? 0;
  out.gananciaEsperadaFmt = gan>=0 ? `S/${gan.toFixed(2)}` : `-S/${Math.abs(gan).toFixed(2)}`;
  out.stakesRounded = out.stakes || {};

  const mktLabels = {'1X2':'⚽ Resultado 1X2','DBL':'🔄 Doble Oportunidad','BTTS':'🥅 Ambos Anotan'};
  out.marketFmt = mktLabels[market] || (market.startsWith('OU_') ? `⬆️ Over/Under ${market.replace('OU_','')}` : market);

  out.tipoLabel = out.tipo==='surebet' ? '🔒 SUREBET (ganancia garantizada)'
    : out.tipo==='valuebet' ? '📈 VALUE BET (cuota con valor)' : '⚪ Sin oportunidad';

  out.ligaFmt = [out.league, out.country].filter(Boolean).join(' · ') || 'Liga desconocida';

  // Fecha partido
  if (out.timestamp) {
    const md    = new Date(Number(out.timestamp)*1000);
    const ahora = new Date();
    const hFmt  = md.toLocaleTimeString('es-PE',{timeZone:'America/Lima',hour:'2-digit',minute:'2-digit'});
    const hoy   = ahora.toLocaleDateString('en-CA',{timeZone:'America/Lima'});
    const man   = new Date(ahora.getTime()+86400000).toLocaleDateString('en-CA',{timeZone:'America/Lima'});
    const fM    = md.toLocaleDateString('en-CA',{timeZone:'America/Lima'});
    out.fechaPartidoFmt = fM===hoy?`Hoy ${hFmt}`:fM===man?`Mañana ${hFmt}`
      :`${md.toLocaleDateString('es-PE',{timeZone:'America/Lima',day:'2-digit',month:'2-digit'})} ${hFmt}`;
    // Datetime legible para Baserow
    out.matchDatetime = `${fM}T${hFmt}:00`;
  } else {
    out.fechaPartidoFmt = 'Fecha desconocida';
    out.matchDatetime   = null;
  }

  const labelOf = l => l==='home'?'Local':l==='draw'?'Empate':l==='away'?'Visitante'
    :l==='over'?'Over':l==='under'?'Under':l==='si'?'Sí':l==='no'?'No'
    :l==='1X'?'1X (Local/Empate)':l==='12'?'12 (Local/Visit.)':l==='X2'?'X2 (Empate/Visit.)':l.toUpperCase();

  const stakes   = out.stakes   || {};
  const outcomes = out.outcomes || [];

  out.stakesDetalle = outcomes
    .filter(o=>stakes[o.label])
    .map(o=>`  ${labelOf(o.label).padEnd(20)}: S/${stakes[o.label]} en ${o.bookmaker}`+(o.url?`\n  🔗 ${o.url}`:''))
    .join('\n');

  out.cuotasDetalle = outcomes
    .filter(o=>o.odds>1)
    .map(o=>`  ${labelOf(o.label).padEnd(20)}: ${o.odds} @ ${o.bookmaker}`+(o.url?`\n  🔗 ${o.url}`:''))
    .join('\n');

  out.valueBetsFmt = (out.valueBets||[]).length>0
    ? out.valueBets.map(v=>`  ${v.label}: cuota ${v.cuota} en ${v.bookmaker} (ROI +${v.roi}%)`+(v.url?`\n  🔗 ${v.url}`:'')+(out.hasPinnacle?` [ref. Pinnacle]`:'')).join('\n')
    : null;

  const horasR   = out.horasRestantes ?? 0;
  const urgencia = horasR<=2 ? '🔴 URGENTE — menos de 2h para el partido'
    : horasR<=6 ? '🟡 Actúa pronto — cuotas cambian en las últimas horas'
    : '🟢 Hay tiempo — verifica cuotas antes de apostar';

  if (out.tipo==='surebet') {
    out.guiaPrincipiante = [
      `━━━━━━ 📚 GUÍA PASO A PASO ━━━━━━`,
      `Ganancia GARANTIZADA. Funciona porque las casas tienen cuotas`,
      `distintas y la suma de probabilidades implícitas < 1.`,
      ``,
      `✅ HAZ ESTO (en orden):`,
      `1. Abre los links de CADA casa (arriba)`,
      `2. VERIFICA que las cuotas coincidan exactamente`,
      `3. Apuesta primero en la cuota MÁS ALTA (cambia más rápido)`,
      `4. Usa los S/ exactos indicados — no redondees`,
      `5. Confirma cada apuesta antes de cerrar la página`,
      ``,
      `⚠️ RIESGOS REALES:`,
      `• Cuotas cambian en minutos — actúa rápido`,
      `• Necesitas saldo en CADA casa simultáneamente`,
      `• No uses Inkabet + Betsson + Betsafe juntas — son la misma empresa`,
      `• Verifica que el partido siga en estado "No iniciado"`,
      ``,
      urgencia
    ].join('\n');
  } else if (out.tipo==='valuebet') {
    const sugerido = Math.round((out.capitalTotal||500)*0.03);
    out.guiaPrincipiante = [
      `━━━━━━ 📚 GUÍA VALUE BET ━━━━━━`,
      `La cuota ofrecida supera el valor matemático.`,
      `No garantiza ganancia hoy, pero es rentable a largo plazo.`,
      out.hasPinnacle ? `📊 Referencia: Pinnacle (la casa más precisa del mundo)` : `📊 Referencia: probabilidad implícita normalizada`,
      ``,
      `💰 Monto sugerido: S/${sugerido} (3% del capital)`,
      `   Solo apuesta si entiendes el mercado: ${out.marketFmt}`,
      ``,
      urgencia
    ].join('\n');
  } else {
    out.guiaPrincipiante = null;
  }

  return { json: out };
});

const threshold = Number($('CONFIG').first().json.CFG_VALUE_THRESHOLD ?? 1.05);

return items.map(item => {
  const d = item.json;
  const { match, market, marketLabel, best, bestDynamic, outcomes,
          stakes, beneficioPct, capitalTotal, capitalApostado, gananciaEsperada,
          currencies, surebet, tipo, riesgo, confianza, comentario,
          league, country, region, horasRestantes, margen, casasDistintas,
          pinnacleRef, pinnacleProb, timestamp } = d;

  const validOutcomes = (outcomes||[]).filter(o=>o.odds>1);
  if (validOutcomes.length===0) return { json:{...d, prob:{}, valueBets:[], roiPct:[]} };

  // Probabilidades: Pinnacle si disponible, implícitas si no
  let prob = {};
  if (pinnacleProb && Object.keys(pinnacleProb).length>0) {
    prob = pinnacleProb;  // más preciso
  } else {
    const sumInv = validOutcomes.reduce((acc,o)=>acc+1/o.odds,0);
    validOutcomes.forEach(o=>{ prob[o.label]=(1/o.odds)/sumInv; });
  }

  const hasPinnacle = !!pinnacleProb && Object.keys(pinnacleProb).length>0;

  const labelOf = l => l==='home'?'Local':l==='draw'?'Empate':l==='away'?'Visitante'
    :l==='over'?'Over':l==='under'?'Under':l==='si'?'Ambos Anotan Sí'
    :l==='no'?'Ambos Anotan No':l.toUpperCase();

  const valueBets = [];
  validOutcomes.forEach(o => {
    const p = prob[o.label] || 0;
    if (p===0) return;
    const val = p * o.odds;
    if (val > threshold) {
      valueBets.push({
        outcome: o.label, label: labelOf(o.label),
        valor: val, roi: ((val-1)*100).toFixed(2),
        bookmaker: o.bookmaker, cuota: o.odds, url: o.url||null,
        probabilidad: (p*100).toFixed(1),
        fuente: hasPinnacle ? 'Pinnacle' : 'implícita'
      });
    }
  });

  return { json: {
    match, market, marketLabel, best, bestDynamic, outcomes,
    league, country, region, horasRestantes, margen, casasDistintas,
    timestamp, pinnacleRef, pinnacleProb, hasPinnacle,
    prob, valueBets, surebet, tipo, riesgo, confianza, comentario,
    stakes, capitalTotal, capitalApostado, gananciaEsperada, currencies,
    beneficioPct, roiPct: valueBets.map(v=>v.roi)
  }};
});

return items.map(item => {
  const rawText = item.json?.text || '';
  let parsed = null;
  if (rawText) {
    let clean = rawText.trim().replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
    try { parsed = JSON.parse(clean); }
    catch(e) { try { const m=clean.match(/\{[\s\S]*\}/); parsed=m?JSON.parse(m[0]):null; } catch(e2){} }
  }
  const llm = {
    tipo:       parsed?.tipo       || 'ninguno',
    riesgo:     parsed?.riesgo     || 'alto',
    confianza:  Number(parsed?.confianza ?? 0),
    comentario: parsed?.comentario || 'Sin análisis'
  };
  const src = $('Loop Over Items').item.json;
  return { json: {
    match:           src.match           ?? null,
    market:          src.market          ?? '1X2',
    marketLabel:     src.marketLabel     ?? '1X2',
    best:            src.best            ?? null,
    bestDynamic:     src.bestDynamic     ?? null,
    outcomes:        src.outcomes        ?? [],
    league:          src.league          ?? null,
    country:         src.country         ?? null,
    region:          src.region          ?? null,
    horasRestantes:  src.horasRestantes  ?? null,
    timestamp:       src.timestamp       ?? null,
    surebet:         src.surebet         ?? false,
    beneficioPct:    src.beneficioPct    ?? 0,
    margen:          src.margen          ?? null,
    stakes:          src.stakes          ?? null,
    capitalTotal:    src.capitalTotal    ?? 500,
    capitalApostado: src.capitalApostado ?? 500,
    gananciaEsperada:src.gananciaEsperada?? 0,
    casasDistintas:  src.casasDistintas  ?? 0,
    currencies:      src.currencies      ?? {},
    pinnacleRef:     src.pinnacleRef     ?? null,
    pinnacleProb:    src.pinnacleProb    ?? null,
    hash:            src.hash            ?? null,
    tipo:       llm.tipo,
    riesgo:     llm.riesgo,
    confianza:  llm.confianza,
    comentario: llm.comentario
  }};
});

