const normalize = str => str
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

// Marcadores de competencia femenina — se excluyen siempre
// independientemente de CFG_LEAGUES
const femeninoMarkers = [
  'women', 'femenino', 'femenina', 'femeni', 'feminine',
  'ladies', 'mujer', 'mujeres', 'female', '(f)', 'woman',
  'frauen',       // alemán
  'femminile',    // italiano
  'feminino',     // portugués
  'feminina',     // portugués
  'feminin',      // francés/rumano
  'dames',        // francés/holandés
  'naiset',       // finlandés
  'kvinder',      // danés
  'damer'         // noruego/sueco
];

const isFemenino = (league) => {
  const norm = normalize(league);
  return femeninoMarkers.some(m => norm.includes(m));
};

const raw    = items[0].json;
const events = raw.events || [];

// Si lista vacía: pasan todos (excepto femeninos siempre)
const sinFiltroLiga = allowedLeagues.length === 0;
const allowedNorm   = allowedLeagues.map(normalize);

const filtered = events.filter(e => {
  const league     = e.league || e.league_raw || '';
  const leagueNorm = normalize(league);

  // Excluir femeninos siempre, sin excepción
  if (isFemenino(league)) return false;

  // Sin filtro de liga configurado: pasa todo lo masculino
  if (sinFiltroLiga) return true;

  // Coincidencia parcial con ligas permitidas
  return allowedNorm.some(allowed =>
    leagueNorm.includes(allowed) || allowed.includes(leagueNorm)
  );
});

const skipped     = events.length - filtered.length;
const femeninos   = events.filter(e => isFemenino(e.league || '')).length;
const fueraLiga   = skipped - femeninos;

console.log(`Filter - ByLeague: ${filtered.length} OK | ${femeninos} femeninos excluidos | ${fueraLiga} fuera de liga`);
console.log('Ligas permitidas:', allowedLeagues);
console.log('Ligas encontradas:', [...new Set(events.map(e => e.league))]);

if (filtered.length === 0) {
  return [{ json: { events: [], _filteredCount: 0, _totalCount: events.length, _femeninosExcluidos: femeninos } }];
}

return [{ json: {
  ...raw,
  events: filtered,
  _filteredCount:       filtered.length,
  _totalCount:          events.length,
  _femeninosExcluidos:  femeninos,
  _fueraLigaExcluidos:  fueraLiga
}}];

