          currencies, surebet, tipo, riesgo, confianza, comentario,
          league, country, region, horasRestantes, margen, casasDistintas,
          pinnacleRef, pinnacleProb, timestamp } = d;

  const validOutcomes = (outcomes||[]).filter(o=>o.odds>1);
  if (validOutcomes.length===0) return { json:{...d, prob:{}, valueBets:[], roiPct:[]} };

  // Probabilidades: Pinnacle si disponible, implícitas si no
  let prob = {};
  if (pinnacleProb && Object.keys(pinnacleProb).length>0) {
    prob = pinnacleProb;  // más preciso
  } else {
    const sumInv = validOutcomes.reduce((acc,o)=>acc+1/o.odds,0);
    validOutcomes.forEach(o=>{ prob[o.label]=(1/o.odds)/sumInv; });
  }

  const hasPinnacle = !!pinnacleProb && Object.keys(pinnacleProb).length>0;

  const labelOf = l => l==='home'?'Local':l==='draw'?'Empate':l==='away'?'Visitante'
    :l==='over'?'Over':l==='under'?'Under':l==='si'?'Ambos Anotan Sí'
    :l==='no'?'Ambos Anotan No':l.toUpperCase();

  const valueBets = [];
  validOutcomes.forEach(o => {
    const p = prob[o.label] || 0;
    if (p===0) return;
    const val = p * o.odds;
    if (val > threshold) {
      valueBets.push({
        outcome: o.label, label: labelOf(o.label),
        valor: val, roi: ((val-1)*100).toFixed(2),
        bookmaker: o.bookmaker, cuota: o.odds, url: o.url||null,
        probabilidad: (p*100).toFixed(1),
        fuente: hasPinnacle ? 'Pinnacle' : 'implícita'
      });
    }
  });

  return { json: {
    match, market, marketLabel, best, bestDynamic, outcomes,
    league, country, region, horasRestantes, margen, casasDistintas,
    timestamp, pinnacleRef, pinnacleProb, hasPinnacle,
