    confianza:  Number(parsed?.confianza ?? 0),
    comentario: parsed?.comentario || 'Sin análisis'
  };
  const src = $('Loop Over Items').item.json;
  return { json: {
    match:           src.match           ?? null,
    market:          src.market          ?? '1X2',
    marketLabel:     src.marketLabel     ?? '1X2',
    best:            src.best            ?? null,
    bestDynamic:     src.bestDynamic     ?? null,
    outcomes:        src.outcomes        ?? [],
    league:          src.league          ?? null,
    country:         src.country         ?? null,
    region:          src.region          ?? null,
    horasRestantes:  src.horasRestantes  ?? null,
    timestamp:       src.timestamp       ?? null,
    surebet:         src.surebet         ?? false,
    beneficioPct:    src.beneficioPct    ?? 0,
    margen:          src.margen          ?? null,
    stakes:          src.stakes          ?? null,
    capitalTotal:    src.capitalTotal    ?? 500,
    capitalApostado: src.capitalApostado ?? 500,
    gananciaEsperada:src.gananciaEsperada?? 0,
    casasDistintas:  src.casasDistintas  ?? 0,
    currencies:      src.currencies      ?? {},
    pinnacleRef:     src.pinnacleRef     ?? null,
    pinnacleProb:    src.pinnacleProb    ?? null,
    hash:            src.hash            ?? null,
    tipo:       llm.tipo,
    riesgo:     llm.riesgo,
    confianza:  llm.confianza,
    comentario: llm.comentario
  }};
});

