parameters.jsCode:
const src = $('Loop Over Items').item.json;
const normalized = {
  match:          src.match          || '',
  league:         src.league         || '',
  country:        src.country        || '',
  market:         src.market         || '1X2',
  marketLabel:    src.marketLabel    || src.market || '1X2',
  margen:         src.margen         ?? null,
  beneficioPct:   src.beneficioPct   ?? 0,
  surebet:        src.surebet        ?? false,
  casasDistintas: src.casasDistintas ?? 0,
  outcomes: (src.outcomes || []).map(o => ({ label:o.label, odds:o.odds, bookmaker:o.bookmaker })),
  hasPinnacle:    !!src.pinnacleProb
};
const hasOdds = normalized.outcomes.length >= 2 && normalized.outcomes.every(o => o.odds > 1);
// Skip LLM si margen > 1.03 — claramente sin oportunidad, ahorra llamadas API
const skipLLM = !hasOdds || (src.margen !== null && src.margen > 1.03 && !src.surebet);
return [{ json: { ...src, normalized, payloadString: JSON.stringify(normalized), skipLLM } }];

// AttachLastHash: fusiona datos de Baserow con el item del Loop
// Detecta si Baserow devolvió una fila existente o está vacío
return items.map(it => {
  const out = { ...it.json };

  const norm = v => {
    if (v === null || v === undefined) return null;
    const s = String(v).trim();
    return (s === '' || s.toLowerCase() === 'null') ? null : s.toLowerCase();
  };

  // El item del Loop tiene el hash calculado
  // El item de Baserow (si existe) tiene 'id' y los campos de la tabla
  const loopItem = $('Loop Over Items').item.json;

  // Recuperar hash calculado desde el Loop
  out.hash = norm(loopItem.hash) || null;

  // Detectar si Baserow devolvió una fila real
  // Una fila de Baserow siempre tiene campo 'id' (número entero)
  const baserowId = out.id ?? null;
  out.baserowRowExists = (baserowId !== null && baserowId !== undefined && baserowId !== '');
  out.baserowRowId = out.baserowRowExists ? baserowId : null;

  // Hash guardado en Baserow (campo que hayas definido)
  const possibleHashKeys = ['Hash', 'hash', 'lastHash', 'last_hash'];
  let savedHash = null;
  for (const k of possibleHashKeys) {
    if (out[k] !== undefined && out[k] !== null && out[k] !== '') {
      savedHash = norm(out[k]);
      break;
    }
  }
  out.lastHash = savedHash;

  // beneficioPct desde Loop (ya calculado en SurebetCalc)
  out.beneficioPct = loopItem.beneficioPct ?? 0;

  return { json: out };
});

const crypto = require('crypto');
return items.map(item => {
  const { match, market, outcomes } = item.json;
  const oddsStr = (outcomes||[])
    .sort((a,b)=>a.label.localeCompare(b.label))
    .map(o=>`${o.label}:${o.odds}:${o.bookmaker}`)
    .join('|');
  const raw  = `${match}||${market}||${oddsStr}`;
  const hash = crypto.createHash('md5').update(raw).digest('hex');
  return { json: { ...item.json, hash } };
});

const parseOdd = (v) => {
  if (v === null || v === undefined) return NaN;
  if (typeof v === 'number') return v > 1 ? v : NaN;
  const num = Number(String(v).trim().replace(',','.'));
  return isFinite(num) && num > 1 ? num : NaN;
};
const round      = (n, d=3) => Math.round(n * Math.pow(10,d)) / Math.pow(10,d);
const roundToInt = (n) => Math.round(n);
const CAPITAL    = Number($('CONFIG').first().json.CFG_CAPITAL ?? 500);
const minCasas   = (market) => (market === '1X2' || market === 'DBL') ? 3 : 2;

return items.map(item => {
  const { match, market, marketLabel, outcomes, best, bestDynamic,
          league, country, region, timestamp, casasDistintas, pinnacleRef } = item.json || {};

  if (!outcomes || outcomes.length === 0)
    return { json: { match, market, marketLabel, error:'sin outcomes', league, country, timestamp } };

  const parsed = outcomes
    .map(o => ({ label:o.label, odds:parseOdd(o.odds), bookmaker:o.bookmaker, url:o.url, currency:o.currency }))
    .filter(o => isFinite(o.odds) && o.odds > 1);

  if (parsed.length < 2)
    return { json: { match, market, marketLabel, league, country, region, timestamp,
      margen:null, surebet:false, beneficioPct:0, stakes:null,
      gananciaEsperada:0, capitalTotal:CAPITAL, casasDistintas:casasDistintas||0,
      best, bestDynamic, outcomes, pinnacleRef, debug:'Cuotas insuficientes' }};

  const sumInv         = parsed.reduce((acc,o) => acc + 1/o.odds, 0);
  const margen         = round(sumInv, 6);
  const minC           = minCasas(market);
  const surebet        = margen < 1 && (casasDistintas || 0) >= minC;
  const beneficioPct   = surebet ? round((1-margen)*100, 3) : 0;

  const stakeMap = {};
  let capitalApostado = CAPITAL, gananciaEsperada = 0;
  if (surebet) {
    parsed.forEach(o => { stakeMap[o.label] = roundToInt((CAPITAL*(1/o.odds))/sumInv); });
    capitalApostado  = Object.values(stakeMap).reduce((a,b)=>a+b,0);
    gananciaEsperada = round(Math.min(...parsed.map(o=>stakeMap[o.label]*o.odds))-capitalApostado,2);
  }

  const bestCompat = {};
  parsed.forEach(o => { bestCompat[o.label] = { odds:o.odds, bookmaker:o.bookmaker, url:o.url, currency:o.currency }; });
  const bestLegacy = market==='1X2'
    ? { home:bestCompat['home']||null, draw:bestCompat['draw']||null, away:bestCompat['away']||null }
    : bestCompat;

  // ── Value con Pinnacle como referencia ──────────────────
  // Si Pinnacle está presente, usamos sus cuotas como probabilidad real
  // Si no, usamos probabilidades implícitas normalizadas
  let pinnacleProb = null;
  if (pinnacleRef && Array.isArray(pinnacleRef) && pinnacleRef.length >= parsed.length) {
    const pinSum = pinnacleRef.slice(0,parsed.length).reduce((a,v)=> v>0 ? a+1/v : a, 0);
    if (pinSum > 0) {
      pinnacleProb = {};
      parsed.forEach((o,i) => {
        const pv = pinnacleRef[i];
        if (pv > 0) pinnacleProb[o.label] = (1/pv)/pinSum;
      });
    }
  }

  return { json: {
    match, market, marketLabel,
    league, country, region, timestamp,
    margen, surebet,
    casasDistintas, beneficioPct, gananciaEsperada, capitalApostado,
    stakes: stakeMap, capitalTotal: CAPITAL,
    best: bestLegacy, bestDynamic: bestCompat,
    outcomes: parsed, pinnacleRef, pinnacleProb,
    currencies: Object.fromEntries(parsed.map(o=>[o.label, o.currency||'PEN']))
  }};
});

// Grupos de clones — misma empresa, NO cuentan como casas distintas
const CLONE_FAMILIES = [
  ['Betsafe','Inkabet','Betsson'],
  ['1xbet','Megapari'],
  ['Cosmobet','Mystake'],
  ['Gangabet','Doradobet','Masterbets365','Atlantic City'],
];
const cloneOf = {};
CLONE_FAMILIES.forEach(fam => { fam.forEach(m => { cloneOf[m] = fam[0]; }); });

const countIndependent = (bookmakerSet) => {
  const seen = new Set();
  let n = 0;
  [...bookmakerSet].forEach(bk => {
    const key = cloneOf[bk] || bk;
    if (!seen.has(key)) { seen.add(key); n++; }
  });
  return n;
};

return items.map(item => {
  const { match, market, marketLabel, offers, league, country, region, timestamp, pinnacleRef } = item.json || {};
  const bestMap = {};

  (offers || []).forEach(offer => {
    const { bookmaker, url, currency, outcomes } = offer;
    (outcomes || []).forEach(({ label, odds }) => {
      if (!odds || odds <= 1) return;
      if (!bestMap[label] || odds > bestMap[label].odds) {
        bestMap[label] = { bookmaker, odds, url, currency };
      }
    });
  });

  const allBks       = new Set(Object.values(bestMap).map(b => b.bookmaker));
  const casasDistintas = countIndependent(allBks);

  // Compatibilidad 1X2
  const bestLegacy = market === '1X2' ? {
    home: bestMap['home'] || null,
    draw: bestMap['draw'] || null,
    away: bestMap['away'] || null
  } : bestMap;

  const outcomesArray = Object.entries(bestMap).map(([label, data]) => ({ label, ...data }));

  return { json: {
    match, market, marketLabel,
    league, country, region, timestamp,
    best:        bestLegacy,
    bestDynamic: bestMap,
    outcomes:    outcomesArray,
    casasDistintas,           // ya descontando clones
    pinnacleRef               // referencia de valor
  }};
});

const arr     = items.map(i => i.json);
const grouped = {};
arr.forEach(r => {
  const key = `${r.match}|||${r.market}`;
  if (!grouped[key]) grouped[key] = [];
  grouped[key].push(r);
});
return Object.keys(grouped).map(key => {
  const [match, market] = key.split('|||');
  const offers = grouped[key];
  return { json: {
    match, market,
    marketLabel: offers[0]?.marketLabel || market,
    offers,
    league:    offers[0]?.league    || null,
    country:   offers[0]?.country   || null,
    region:    offers[0]?.region    || null,
    timestamp: offers[0]?.timestamp || null,
    pinnacleRef: offers.find(o => o.bookmaker === 'Pinnacle')?.pinnacleRef || null
  }};
});

const raw    = items[0].json;
const events = raw.events || [];

const currencyMap = {
  'Peru':'PEN','Brazil':'BRL','Argentina':'ARS','Chile':'CLP',
  'Colombia':'COP','Uruguay':'UYU','South America':'PEN',
  'England':'GBP','Spain':'EUR','Germany':'EUR','Italy':'EUR',
  'France':'EUR','Netherlands':'EUR','Portugal':'EUR','Europe':'EUR',
  'United States':'USD','Mexico':'MXN','Canada':'CAD','North America':'USD',
  'Japan':'JPY','China':'CNY','South Korea':'KRW','default':'USD'
};

// OU umbrales permitidos — solo los líquidos
const ALLOWED_OU = new Set(['1.5','2.5','3.5']);

const parseOddValue = (v) => {
  if (v === null || v === undefined) return null;
  if (typeof v === 'number')  return v > 1 ? v : null;
  if (typeof v === 'object' && v.price !== undefined) return v.price > 1 ? v.price : null;
  const n = parseFloat(String(v));
  return isFinite(n) && n > 1 ? n : null;
};

// Clones — excluir al calcular casas independientes (se propagan a BestOdds)
const CLONE_FAMILIES = [
  ['Betsafe','Inkabet','Betsson'],
  ['1xbet','Megapari'],
  ['Cosmobet','Mystake'],
  ['Gangabet','Doradobet','Masterbets365','Atlantic City'],
];
const cloneOf = {};
CLONE_FAMILIES.forEach(fam => {
  const canonical = fam[0];
  fam.forEach(m => { cloneOf[m] = canonical; });
});

const normalized = [];

events.forEach(e => {
  const match     = `${e.homeTeam} vs ${e.awayTeam}`;
  const timestamp = e.timestamp;
  const league    = e.league  || null;
  const country   = e.country || null;
  const region    = e.region  || null;
  const bookmakers = e.canonical?.bookmakers || {};

  // Pinnacle como referencia de valor (si existe)
  const pinnacleOdds = bookmakers['Pinnacle']?.odds || null;

  Object.keys(bookmakers).forEach(bk => {
    const bkData   = bookmakers[bk];
    const allOdds  = bkData.odds || {};
    const url      = bkData.url  || null;
    const currency = bkData.currency || currencyMap[country] || currencyMap['default'];
    // Familia canónica para detectar clones
    const canonicalFamily = cloneOf[bk] || bk;
    const base = { match, timestamp, league, country, region, bookmaker: bk, canonicalFamily, url, currency };

    // ── 1X2 + PA + SC ────────────────────────────────────────
    ['1X2','1x2','PA','SC'].forEach(src => {
      const arr = allOdds[src];
      if (!arr || !Array.isArray(arr) || arr.length < 3) return;
      const h = parseOddValue(arr[0]);
      const d = parseOddValue(arr[1]);
      const a = parseOddValue(arr[2]);
      if (!h || !d || !a) return;
      normalized.push({
        ...base, market:'1X2', marketKey: src,
        outcomes:[{label:'home',odds:h},{label:'draw',odds:d},{label:'away',odds:a}],
        pinnacleRef: pinnacleOdds?.['1X2'] || null
      });
    });

    // ── DBL ──────────────────────────────────────────────────
    const rawDBL = allOdds['DBL'];
    if (rawDBL && Array.isArray(rawDBL) && rawDBL.length >= 3) {
      const d1X = parseOddValue(rawDBL[0]);
      const d12 = parseOddValue(rawDBL[1]);
      const dX2 = parseOddValue(rawDBL[2]);
      if (d1X && d12 && dX2) {
        normalized.push({
          ...base, market:'DBL', marketLabel:'Doble Oportunidad',
          outcomes:[{label:'1X',odds:d1X},{label:'12',odds:d12},{label:'X2',odds:dX2}]
        });
      }
    }

    // ── Over/Under — solo 1.5 / 2.5 / 3.5 ───────────────────
    Object.keys(allOdds).filter(k => k.startsWith('Over/Under')).forEach(key => {
      const arr = allOdds[key];
      if (!arr || !Array.isArray(arr) || arr.length < 2) return;
      const over  = parseOddValue(arr[0]);
      const under = parseOddValue(arr[1]);
      if (!over || !under) return;
      const m = key.match(/(\d+\.?\d*)/);
      const line = m ? m[1] : null;
      if (!line || !ALLOWED_OU.has(line)) return;   // filtro umbrales
      normalized.push({
        ...base, market:`OU_${line}`, marketLabel:`Over/Under ${line}`,
        outcomes:[{label:'over',odds:over},{label:'under',odds:under}],
        pinnacleRef: pinnacleOdds?.[key] || null
      });
    });

    // ── BTTS ─────────────────────────────────────────────────
    const rawBTTS = allOdds['BTTS'];
    if (rawBTTS && Array.isArray(rawBTTS) && rawBTTS.length >= 2) {
      const si = parseOddValue(rawBTTS[0]);
      const no = parseOddValue(rawBTTS[1]);
      if (si && no) {
        normalized.push({
          ...base, market:'BTTS', marketLabel:'Ambos Anotan',
          outcomes:[{label:'si',odds:si},{label:'no',odds:no}],
          pinnacleRef: pinnacleOdds?.['BTTS'] || null
        });
      }
    }
  });
});

return normalized.map(r => ({ json: r }));

const cfg = $('CONFIG').first().json;
const horaInicio = cfg.CFG_HORA_INICIO ?? 8;
const horaFin = cfg.CFG_HORA_FIN ?? 23;

const hour = Number(
  new Date().toLocaleString('en-US', {
    hour: 'numeric',
    hour12: false,
    timeZone: 'America/Lima'
  })
);

return [
  {
    json: {
      ...cfg,
      horaPeru: hour,
      dentroHorario: (hour >= horaInicio && hour < horaFin)
    }
  }
];
